"""
mkt-christ fill — 1 Kings ch20-21
Covers: 48 missing verses (ch20: 1-28; ch21: 1-12, 14-18, 20-22)
Run: python3 scripts/zc-christ-1kings-20-21-fill.py
"""

import json
import pathlib

def load_comm(path):
    p = pathlib.Path(path)
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(path, data):
    pathlib.Path(path).write_text(json.dumps(data, ensure_ascii=False, indent=2))

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

DATA = {
"20": {
"1": "<p>Ben-hadad of Syria gathers thirty-two vassal kings and lays siege to Samaria. The coalition of surrounding nations against the city of the covenant people is an eschatological pattern: Revelation&#8217;s vision of the nations surrounding the beloved city (Rev 20:9) ends not by human victory but by fire from heaven. Here too, Israel&#8217;s deliverance will not come through military strength but through YHWH vindicating his name against the Syrians&#8217; theological error.</p>",
"2": "<p>Ben-hadad&#8217;s messengers deliver an ultimatum: &lsquo;Your silver and gold are mine; your wives and best children are mine.&rsquo; The demand amounts to total vassalage &#8212; surrender of what is most precious as the condition of peace. The false lord who demands total surrender of what belongs to God inverts the proper direction of covenant: YHWH asks for everything freely given in love; Ben-hadad demands it under threat of destruction.</p>",
"3": "<p>Ahab&#8217;s capitulation &#8212; &lsquo;As you say, my lord, I am yours and all I have&rsquo; &#8212; uses language that echoes covenant surrender. The phrase &lsquo;I am yours&rsquo; (<em>l&#601;&#7717;&#257; &#703;&#259;n&#238;</em>) in its proper register belongs to YHWH: &lsquo;You are my Lord; I have no good apart from you&rsquo; (Ps 16:2). Ahab renders to human imperial power what belongs to God alone &#8212; the total submission of person and possessions that is covenant loyalty rendered to the wrong lord.</p>",
"4": "<p>&lsquo;I am yours, my lord king, and all I have.&rsquo; Ahab&#8217;s formula of complete surrender closes the first exchange. The gospel reversal of this pattern appears in Paul: &lsquo;you are not your own, for you were bought with a price&rsquo; (1 Cor 6:19&#8211;20) &#8212; total belonging rendered to Christ, the legitimate Lord. What Ahab surrenders to the wrong lord out of fear, the believer surrenders to the right Lord out of gratitude for redemption.</p>",
"5": "<p>Ben-hadad escalates: his messengers will come and search Ahab&#8217;s house and the houses of his servants to take whatever is desirable. The escalation from formal tribute to unlimited plunder reveals the logic of empire: submission invites exploitation. No covenant with worldly power offers true security; only the covenant with YHWH offers the rest and safety that empire promises but cannot deliver.</p>",
"6": "<p>The messengers will seize &lsquo;whatever is desirable in your eyes&rsquo; &#8212; turning Ahab&#8217;s own desiring gaze against him. What the eyes covet becomes the leverage of the exploiter. The pattern of desire manipulated as vulnerability runs through Judges and Kings: what Israel coveted &#8212; the nations&#8217; gods, their kings, their alliances &#8212; became the instrument of judgment. Christ redirects desire: &lsquo;seek first the kingdom of God&rsquo; (Matt 6:33), and what is truly desirable will be added.</p>",
"7": "<p>Ahab convenes the elders of the land: &lsquo;See how this man seeks trouble.&rsquo; The recognition of bad faith &#8212; seeing exploitation for what it is &#8212; begins the turn from submission to resistance. Communal discernment of the elders functions as corporate wisdom that restrains the king&#8217;s impulse. The NT church&#8217;s eldership (1 Tim 4:14; Acts 15:6) performs the same function: collective testing of whether demands made on the community are legitimate or exploitative.</p>",
"8": "<p>The elders&#8217; counsel: &lsquo;Do not listen or consent.&rsquo; The simple refusal of the unjust demand is the beginning of covenant faithfulness. Martyrs and confessors throughout church history &#8212; from Daniel&#8217;s refusal to stop praying to the early church&#8217;s refusal to offer incense &#8212; inhabit this same &lsquo;do not listen or consent.&rsquo; The boundary between reasonable accommodation and covenant betrayal is what the elders help Ahab locate.</p>",
"9": "<p>Ahab&#8217;s distinction &#8212; &lsquo;all that you first demanded I will do, but this thing I cannot do&rsquo; &#8212; separates tribute from desecration. Even in a compromised king there is a point at which &lsquo;I cannot&rsquo; becomes a confession of covenant loyalty. The NT version is Peter and John before the Sanhedrin: &lsquo;Whether it is right in the sight of God to listen to you rather than to God, you must judge&rsquo; (Acts 4:19) &#8212; the moment when compliance becomes impossible because it requires betrayal.</p>",
"10": "<p>Ben-hadad&#8217;s hyperbolic threat: if enough of Samaria&#8217;s dust suffices for handfuls among his soldiers, he will destroy it utterly. Destruction threats designed to compel surrender are the vocabulary of every empire before its armies. The NT response to such threats is calibrated: &lsquo;Do not fear those who kill the body but cannot kill the soul&rsquo; (Matt 10:28). The ultimate threat &#8212; annihilation &#8212; loses its power over those whose life is hidden with Christ in God (Col 3:3).</p>",
"11": "<p>Ahab&#8217;s proverb: &lsquo;Let not him who puts on his armor boast like him who takes it off.&rsquo; Only the veteran of completed battle may boast. Paul draws on the same principle: &lsquo;I have fought the good fight, I have finished the race, I have kept the faith&rsquo; (2 Tim 4:7) &#8212; the boast comes at the end, not the beginning. Ben-hadad&#8217;s pre-battle boast will be answered by disaster.</p>",
"12": "<p>Ben-hadad and his allied kings are drinking in their booths when the reply arrives. Power that celebrates before the battle is power that cannot see its own defeat approaching. Drinking feasts punctuate Israel&#8217;s enemy narratives at the moments of greatest vulnerability (cf. Belshazzar, Dan 5:1&#8211;4). The great empires of Revelation are characterized by intoxication before their fall (Rev 18:3).</p>",
"14": "<p>The unnamed prophet&#8217;s oracle designates the young men of the district governors as the instrument of victory &#8212; 232 men at the vanguard of 7,000. The improbable instrument echoes Gideon&#8217;s 300: YHWH chooses small numbers to ensure the victory cannot be attributed to human strength. &lsquo;Not by might, nor by power, but by my Spirit&rsquo; (Zech 4:6) is the theological constant behind every such improbable victory.</p>",
"15": "<p>Ahab musters 7,000 behind the 232 young men. The 7,000 who have not bowed to Baal (1 Kgs 19:18) stand as the hidden reserve of covenant faithfulness; here 7,000 mustered at the noon hour become the instrument of YHWH&#8217;s vindication against Syria&#8217;s theological presumption. Divine appointment, not human calculation, determines who leads.</p>",
"16": "<p>They go out at noon &#8212; the Syrians are still drinking. Noon is the hour of divine appointment in Israel&#8217;s story (Amos 8:9: &lsquo;I will make the sun go down at noon&rsquo;; the darkness at the crucifixion beginning at the sixth hour). What looks like a military advantage is a moment of divine arrangement. The one who controls time can deploy it against every presumption of the powerful.</p>",
"17": "<p>Ben-hadad&#8217;s scouts report men coming from Samaria; his command &#8212; &lsquo;take them alive, whether for peace or war&rsquo; &#8212; misreads the situation entirely. The plan to take prisoners assumes that these small numbers represent a negotiating gesture, not a military attack. False confidence blinds to the reality of the divine strategy: what looks like a small advance party is the beginning of total defeat.</p>",
"18": "<p>Ben-hadad&#8217;s order to take prisoners alive is overtaken by events: the young men break through before it can be executed. The human plan (hostage-taking, negotiation, management of the conflict) is simply bypassed by the speed of the divinely enabled rout. The attempt to control what YHWH has set in motion is the characteristic failure of those who encounter the divine action without recognizing it.</p>",
"19": "<p>Israel strikes down horses and chariots with a great slaughter. The targeting of the military apparatus reflects the covenant theology of holy war: not personal enmity but the dismantling of opposing power structures. David&#8217;s hamstringing of the horses (2 Sam 8:4) reflects the same principle: the war horse is the emblem of the power that opposes trust in YHWH (Ps 20:7: &lsquo;some trust in chariots and horses, but we trust in the name of the LORD&rsquo;).</p>",
"20": "<p>Each man kills his man; the Syrians flee, and Ben-hadad escapes on a horse with his cavalry. The totality of the rout is undercut by the escape of the condemned king. This irresolution &#8212; the victory complete, the guilty party escaped &#8212; creates the theological tension the chapter will resolve. The guilty survivor who escapes by speed will return for judgment through the prophet&#8217;s word.</p>",
"21": "<p>Ahab pursues the Syrians with his horsemen. What matters is what Ahab does not do: he does not put Ben-hadad under <em>h&#803;&#275;rem</em> (the devoted destruction YHWH will later reveal was required). The victorious king who pursues horses and chariots while letting the condemned king escape is the picture of action at the wrong level: military thoroughness accompanied by covenantal failure.</p>",
"22": "<p>The prophet warns Ahab to strengthen himself, for Ben-hadad will return the following year. Prophetic realism after victory &#8212; present triumph does not guarantee future security &#8212; is the pattern of wise counsel in the covenant. The disciples&#8217; pattern of prayer after miraculous provision (Mark 6:46, after the feeding of the five thousand) models the vigilance required after divine action. Victory is not the end of the story; it is the test of what follows.</p>",
"23": "<p>Ben-hadad&#8217;s advisers conclude that YHWH is a &lsquo;god of the hills&rsquo; (<em>&#702;&#277;l&#333;h&#234; h&#257;r&#238;m</em>) &#8212; fight in the valleys and Israel will lose. The geographical limitation assigned to YHWH is the classic form of pagan reductionism: every deity has its domain, its territory, its conditions. The Syrians name the test they are about to fail. The comprehensive lordship of the God of Israel &#8212; Creator of hill and valley &#8212; is about to be publicly demonstrated at their expense.</p>",
"24": "<p>The Syrians replace the coalition kings with professional commanders &#8212; strategic reorganization after defeat. The substitution of royal coalition with military expertise reflects rational thinking: politics lost the first battle, expertise should win the second. But the problem was never command structure; it was the theological presumption of v23. Reorganizing the army while retaining the false theology simply delivers a better-organized army into the same judgment.</p>",
"25": "<p>Syria assembles an army matching its losses &#8212; horse for horse, chariot for chariot &#8212; to fight the rematch at Aphek. The systematic rebuilding of what was destroyed models the persistence of every power that opposes the covenant. Peter&#8217;s warning &#8212; &lsquo;your adversary the devil prowls around like a roaring lion&rsquo; (1 Pet 5:8) &#8212; captures the pattern: defeat does not end the opposition; it restructures it. Vigilance must be permanent, not seasonal.</p>",
"26": "<p>Israel camps before Syria &lsquo;like two little flocks of goats.&rsquo; The visual disproportion &#8212; tiny Israel against vast Syria &#8212; is the staging of every redemptive improbability in Scripture. The logic of the incarnation itself is this visual disproportion: God becomes a child, the King of Kings is born in a feed trough. The &lsquo;little flock&rsquo; (Luke 12:32) is not mistaken about its size; the size is the condition of the demonstration.</p>",
"27": "<p>Syria fills the countryside. The verse sets the maximum contrast between human optics and the divine outcome that follows. Optics &#8212; what appears overwhelming by every calculation &#8212; are the canvas on which divine power is displayed. The disciples&#8217; panic before the 5,000 (&lsquo;Two hundred denarii would not buy enough bread for each of them to get a little,&rsquo; John 6:7) stands in the same tradition of impossible arithmetic dissolved by divine provision.</p>",
"28": "<p>The man of God declares: &lsquo;Because the Syrians have said, YHWH is a god of the hills but not of the valleys, I will give all this great multitude into your hand, and you shall know that I am YHWH.&rsquo; YHWH fights to vindicate his name against the limitation his enemies assign him. The christological fulfillment is the universal lordship declared in the resurrection: &lsquo;All authority in heaven and on earth has been given to me&rsquo; (Matt 28:18) &#8212; the categorical refusal of every geographical, spatial, or temporal limitation on divine sovereignty.</p>",
"29": "<p>Israel strikes down 100,000 Syrian foot soldiers in a single day. The &lsquo;one day&rsquo; specification intensifies the contrast: what no human army could accomplish in months is accomplished before sundown. The eschatological resonance points toward the day of the LORD when the accumulated power of every opposing kingdom is broken in a moment of divine action (Rev 19:20&#8211;21).</p>",
"30": "<p>Twenty-seven thousand more die when the city wall of Aphek falls on them. The earth itself cooperates with the divine verdict: not just the army but the physical infrastructure of the besieging power collapses. &lsquo;The stones will cry out&rsquo; (Luke 19:40) is the positive version; here the stones kill. Creation actively participates in YHWH&#8217;s judgments &#8212; the sea swallows the Egyptian army, the ground swallows Korah, the wall of Aphek crushes the Syrian survivors. The physical world is not neutral toward covenant treachery.</p>",
"31": "<p>Ben-hadad&#8217;s servants advise sackcloth and ropes around their necks &#8212; the ancient surrender ritual. They appeal to <em>h&#803;eseḏ</em> (covenant-kindness), claiming that Israelite kings are &lsquo;merciful kings.&rsquo; The appeal assumes a quality Ben-hadad has not earned; he can only plead for grace, not right. Ahab&#8217;s response will show that misplaced <em>h&#803;eseḏ</em> toward the condemned is itself a covenant violation, not an expression of it.</p>",
"32": "<p>Ben-hadad&#8217;s servants speak with ropes around their necks: &lsquo;Please let me live.&rsquo; Ahab&#8217;s response &#8212; &lsquo;Is he still alive? He is my brother&rsquo; &#8212; reveals the fatal sentimentality that will cost him his life. Calling the condemned king &lsquo;brother&rsquo; (<em>&#702;&#257;h&#238;</em>) is Ahab&#8217;s covenantal error: treating as a covenant partner one whom YHWH has condemned. The NT distinction between brotherly love within the covenant community and accommodation of what God has condemned (1 Cor 5:9&#8211;11) maps precisely onto this failure.</p>",
"33": "<p>Ben-hadad is brought up into the chariot; Ahab makes a covenant with him, returning cities and granting trading rights in Damascus. The covenant made with the condemned is Ahab&#8217;s second great failure after the worship of Baal. Political accommodation of the enemy of the covenant &#8212; negotiating away covenantal rights for commercial advantage &#8212; is the pattern that leads Israel into apostasy. Every &lsquo;covenant&rsquo; with what YHWH has devoted to destruction becomes a covenant against YHWH himself.</p>",
"34": "<p>Ben-hadad&#8217;s terms: restore the cities, grant bazaar rights in Damascus. The chapter&#8217;s resolution reads as pragmatic diplomacy. The theological verdict comes through the prophet&#8217;s subsequent parable: Ahab has done exactly what a soldier condemned to death for losing his prisoner does. Pragmatic diplomacy that contradicts YHWH&#8217;s verdict is not wisdom but self-condemnation dressed in the language of statecraft.</p>",
"35": "<p>A member of the prophetic company asks a colleague to strike him; the refusal results in a lion&#8217;s attack and death. The strange enacted judgment on the disobedient prophet establishes the seriousness of refusing the prophetic symbolic action. Prophetic obedience extends to apparently violent or strange commands: what YHWH asks must be done regardless of how it appears to human moral categories. The boundary between the sacred and the accommodating is maintained by severe consequences.</p>",
"36": "<p>The second colleague strikes the prophet, wounding him. The obedience of the second man and the death of the first shows that the prophetic word&#8217;s authority is not negotiable even among prophets. The community of those called to speak God&#8217;s word must itself be under that word&#8217;s authority. Those who bear the prophetic word are most accountable to it, not least.</p>",
"37": "<p>The prophet disguises himself with a bandage over his eyes and waits for the king on the road. The disguise enables the parable technique: presenting the situation in narrative form to extract the king&#8217;s own judgment before applying it to him. Nathan&#8217;s parable of the ewe lamb (2 Sam 12:1&#8211;4) uses the same method. Christ&#8217;s parables of judgment (Matt 21:33&#8211;41) operate on the same principle: truth approaches power through indirection and leads the hearer to condemn themselves before the application lands.</p>",
"38": "<p>The wounded prophet waits for the king and tells his parable: &lsquo;Your servant was in the battle; a man turned and brought a prisoner to me, saying, Keep this man.&rsquo; The prisoner-of-war language maps directly onto the <em>h&#803;&#275;rem</em> situation: Ben-hadad was YHWH&#8217;s prisoner of war, devoted to destruction, entrusted to Ahab for execution. The parable narrows the application of the covenant concept by placing it in familiar military terms.</p>",
"39": "<p>&lsquo;If he is missing, your life shall be for his life, or you shall pay a talent of silver.&rsquo; Ahab hears the case and pronounces: &lsquo;So shall your judgment be; you yourself have decided it.&rsquo; The king&#8217;s self-incriminating verdict parallels David&#8217;s &lsquo;The man who has done this deserves to die&rsquo; (2 Sam 12:5) &#8212; the prophetic trap that allows justice to speak through the sinner&#8217;s own mouth. Condemnation from one&#8217;s own acknowledged standards is the most unanswerable form of judgment.</p>",
"40": "<p>&lsquo;While your servant was busy here and there, he was gone.&rsquo; The distraction defense &#8212; preoccupied with other things, the prisoner escaped &#8212; is Ahab&#8217;s story precisely: while busy with diplomacy and commercial advantage, he let the condemned go. Dispersed attention as the cause of covenant failure is the warning of the Sermon on the Mount: &lsquo;No one can serve two masters&rsquo; (Matt 6:24). Covenant faithfulness cannot be maintained alongside competing loyalties.</p>",
"41": "<p>The prophet removes his disguise; Ahab recognizes him as one of the prophets. The dramatic recognition scene &#8212; the disguised prophet revealed &#8212; is the moment of application. What seemed like a legal case about a soldier&#8217;s negligence is suddenly the king&#8217;s own verdict on himself. Every parable of Christ functions this way: the Pharisee who agrees that the wicked tenants deserve destruction (Matt 21:41) has just condemned himself.</p>",
"42": "<p>&lsquo;Because you have let go the man whom I had devoted to destruction, your life shall be for his life, and your people for his people.&rsquo; The <em>h&#803;&#275;rem</em> principle is precise: the devoted one was YHWH&#8217;s prisoner; Ahab released him; the judgment transfers. Misplaced mercy toward the condemned does not cancel the judgment &#8212; it only reroutes it. Christ&#8217;s substitutionary death is the one case where the judgment is properly transferred: he, the sinless one, bears the <em>h&#803;&#275;rem</em> that falls on the condemned, absorbing it rather than dismissing it.</p>",
"43": "<p>Ahab returns home &lsquo;sullen and vexed&rsquo; (<em>sar w&#277;z&#257;&#703;&#275;p</em>) &#8212; the same phrase as 20:43 and 21:4. A king who sulks when corrected by prophet or covenant obligation is constitutionally incapable of repentance. The Pharisees&#8217; going away &lsquo;grieved&rsquo; from Christ&#8217;s hard sayings (Matt 19:22 &#8212; the rich young man) is the NT version of this sullen departure from the word of truth.</p>"
},
"21": {
"1": "<p>Naboth the Jezreelite had a vineyard beside the palace of Ahab king of Samaria. The geographical juxtaposition &#8212; the king&#8217;s palace beside the commoner&#8217;s vineyard &#8212; is the spatial setup for covetousness. The covenant boundary between palace property and Israelite family heritage reflects the land theology of Lev 25:23: &lsquo;the land is mine; you are strangers and sojourners with me.&rsquo; The vineyard is not merely Naboth&#8217;s but YHWH&#8217;s entrusted possession, held by Naboth as tenant-heir.</p>",
"2": "<p>Ahab&#8217;s request is framed as a reasonable transaction: he will give a better vineyard or pay money. The proposal is not inherently wicked; it is the refusal that reveals the covenant issue. Ahab&#8217;s motive &#8212; &lsquo;that I may have it for a vegetable garden&rsquo; &#8212; is entirely domestic: proximity and convenience, not ideology. The smallness of the motive makes the subsequent murder all the more damning. Great evil often begins with small coveting of what is close at hand (cf. 2 Sam 11:2).</p>",
"3": "<p>Naboth&#8217;s refusal: &lsquo;YHWH forbid that I should give you the inheritance of my fathers.&rsquo; The Hebrew <em>nah&#780;&#780;&#277;l&#257;h</em> (inheritance, heritage) carries full covenantal weight: land allotted by YHWH to each family as their share in the covenant (Num 36:7&#8211;9; Lev 25:13&#8211;28). Naboth is not being stubborn; he is being covenant-faithful, refusing to alienate what YHWH has entrusted to his family. The willingness to lose possessions rather than betray covenant trust is the foundational pattern of martyrdom.</p>",
"4": "<p>Ahab goes home &lsquo;sullen and vexed&rsquo; &#8212; the same phrase as 20:43. The repetition of the sulking pattern establishes it as Ahab&#8217;s characteristic response to covenantal refusal: he will not eat. The king who cannot eat because a commoner has maintained his covenant right is a king whose personal desire has displaced the covenant as the frame of reality. Ahab&#8217;s refusal to accept &lsquo;no&rsquo; will unleash Jezebel&#8217;s machinery of murder.</p>",
"5": "<p>Jezebel asks: &lsquo;Why is your spirit so vexed that you eat no food?&rsquo; Her question opens the way for the scheme that follows. Jezebel&#8217;s pragmatism &#8212; kings get what they want &#8212; is the logic of power unrestrained by covenant. The contrasting figure is Joseph&#8217;s refusal of Potiphar&#8217;s wife: &lsquo;How then can I do this great wickedness and sin against God?&rsquo; (Gen 39:9). Where Joseph refuses what is near because of covenant loyalty, Ahab enables what is near because he lacks the covenant loyalty to restrain him.</p>",
"6": "<p>Ahab recounts his request and Naboth&#8217;s refusal. His framing &#8212; presenting the transaction as entirely reasonable and Naboth&#8217;s refusal as arbitrary &#8212; omits the covenantal reason (&lsquo;YHWH forbid&rsquo;). The absence of the theological grounding from Ahab&#8217;s retelling to Jezebel reveals what he does not want to hear: that Naboth&#8217;s refusal is grounded in something higher than personal preference, something Jezebel&#8217;s scheme will require overriding.</p>",
"7": "<p>&lsquo;Do you now govern Israel? Arise and eat and let your heart be cheerful; I will give you the vineyard of Naboth.&rsquo; Jezebel&#8217;s taunt inverts covenant kingship: she implies that governing Israel means getting whatever the king wants. The true model of Davidic kingship is the shepherd-king who protects the flock (Ezek 34:2&#8211;4); Jezebel&#8217;s model is the king who exploits whatever is near. Her &lsquo;I will give you&rsquo; mimics divine provision while planning murder &#8212; the false provider who offers what God in his wisdom withholds.</p>",
"8": "<p>Jezebel writes letters in Ahab&#8217;s name and seals them with his seal &#8212; appropriating royal authority for private murder. The misuse of the king&#8217;s seal for Naboth&#8217;s murder is the structure of institutional evil: using legitimate forms (royal seal, legal assembly, covenant fast) to accomplish a predetermined crime. Christ&#8217;s trial before the Sanhedrin follows the same pattern &#8212; legal forms weaponized against the innocent (Matt 26:59&#8211;60).</p>",
"9": "<p>The letters instruct the city elders to proclaim a fast and set Naboth at the head of the people. Sacred time and civic space are commandeered to give the murder the appearance of legal process. The manipulation of religious forms for political ends &#8212; calling evil sacred &#8212; is one of Scripture&#8217;s most consistent targets of prophetic condemnation (Isa 1:11&#8211;15; Matt 23:23&#8211;28). The fast meant to honor YHWH becomes the frame for murdering his covenant-faithful servant.</p>",
"10": "<p>&lsquo;Set two worthless men over against him and let them bring a charge against him.&rsquo; The two witnesses required by Mosaic law for a capital charge (Deut 17:6) are consciously deployed but with &lsquo;sons of Belial&rsquo; (<em>b&#279;n&#234; b&#277;liyya&#703;al</em>) as accusers. The legal form &#8212; two witnesses &#8212; is preserved while the substance is inverted. False witnesses against Naboth directly parallel the false witnesses mobilized against Christ (Matt 26:59&#8211;60). Institutional religion&#8217;s gravest sin is using covenant procedure to murder the covenant-faithful.</p>",
"11": "<p>The men of the city &#8212; elders and nobles &#8212; do exactly as Jezebel&#8217;s letters specify. The communal compliance with unjust power is as culpable as the originating command. Those who &lsquo;only followed orders&rsquo; are judged alongside those who gave them. The silence and compliance of the community in the face of judicial murder is a form of participation; Ezekiel&#8217;s watchman theology (Ezek 33:6) holds the community accountable for what it permits through inaction or acquiescence.</p>",
"12": "<p>They proclaim the fast and set Naboth at the head of the people &#8212; placing the accused in the position of honor before stripping it from him publicly. The elevation before the fall is a feature of public shaming: the accused is made conspicuous precisely to be cast down before the assembled witnesses. The perverse elevation designed to destroy inverts the messianic pattern: Christ is lifted up not to shame but to draw all people to himself (John 12:32), the exaltation that saves.</p>",
"14": "<p>&lsquo;Naboth has been stoned; he is dead.&rsquo; The bare report &#8212; mission accomplished, innocent man murdered &#8212; is delivered to Jezebel without narrative comment or expression of regret. The bureaucratic flatness of the murder report is the voice of systematic evil: efficient, unfeeling, complete. The same detachment marks the Sanhedrin&#8217;s delivery of Jesus to Pilate &#8212; the institutional machinery accomplishes the murder, its operatives insulated from its moral weight by the procedural distance between command and act.</p>",
"15": "<p>Jezebel tells Ahab to arise and take possession of the vineyard Naboth refused to sell, &lsquo;for Naboth is not alive but dead.&rsquo; The four-beat narrative of possession &#8212; arose, went down, took possession &#8212; is the measured account of covenant violation proceeding to completion. The vineyard purchased with innocent blood is now claimed. Zechariah 5:3&#8211;4 describes the curse that enters the house of the thief and the false swearer &#8212; what Ahab enters with his step into the vineyard is already marked for judgment.</p>",
"16": "<p>Ahab goes down to the vineyard to take possession. The action is the completion of a process that began with covetousness, was enabled by passive weakness, and was accomplished by another&#8217;s murder. Ahab&#8217;s hands are not technically on the murder weapon, but his soul is fully implicated: he coveted, he sulked, he told Jezebel, he received the report, and he went to possess. The vineyard parable of Matt 21:33&#8211;41, where the tenants kill the heir to seize the inheritance, draws on precisely this Naboth-Ahab pattern.</p>",
"17": "<p>YHWH commands Elijah: &lsquo;Arise, go down to meet Ahab king of Israel; behold, he is in the vineyard of Naboth, where he has gone to take possession.&rsquo; The specificity of the divine command &#8212; YHWH knows precisely where Ahab is and why &#8212; models the omniscience that grounds prophetic confrontation. Nothing is hidden: not the letters written in secret, the false assembly, the stoning, the report, the immediate possession. The prophet is sent not with general instructions but with exact intelligence about a crime YHWH witnessed in full.</p>",
"18": "<p>&lsquo;You shall say to him, Thus says YHWH: Have you killed, and also taken possession?&rsquo; The prophetic formula <em>k&#333;h &#702;&#257;mar YHWH</em> invests the messenger with the authority of the divine sender. Elijah&#8217;s two-question indictment names both crimes: murder and theft. The conjunction &lsquo;and also&rsquo; makes clear that the second crime is inseparable from the first. Possession acquired through injustice is not ownership but ongoing crime. Zacchaeus&#8217;s fourfold restoration (Luke 19:8) is the repentance pattern: acknowledging that possession acquired unjustly must be returned.</p>",
"20": "<p>&lsquo;Have you found me, O my enemy?&rsquo; (<em>h&#277;m&#257;&#7779;&#257;&#702;t&#257;n&#238; &#702;&#333;y&#277;b&#238;</em>). Ahab&#8217;s recognition of Elijah as his enemy reveals the deepest distortion of covenantal perception: the prophet sent by God is categorized as personal adversary. Truth-tellers who disrupt the comfortable possession of ill-gotten gains become enemies in the eyes of those who benefit from injustice. Christ&#8217;s prophetic disruption of the temple (John 2:13&#8211;17) and his condemnation of the scribes and Pharisees (Matt 23:13&#8211;36) provoked the same re-categorization: the Lord of the house is declared the enemy of those who have made it a den of robbers.</p>",
"21": "<p>Elijah&#8217;s doom oracle: &lsquo;Behold, I will bring disaster upon you. I will utterly burn you up, and will cut off from Ahab every male, bond or free, in Israel.&rsquo; The oracle mirrors the destruction of Jeroboam&#8217;s and Baasha&#8217;s houses &#8212; Ahab&#8217;s sin places him in the succession of covenant-violating kings whose dynasties are ended by divine judgment. Persistent covenant violation produces the covenant curses of Deut 28:15&#8211;68 not as arbitrary punishment but as the working out of what the covenant always contained.</p>",
"22": "<p>&lsquo;I will make your house like the house of Jeroboam the son of Nebat and like the house of Baasha the son of Ahijah, because you have made Israel to sin.&rsquo; The phrase &lsquo;made Israel to sin&rsquo; (<em>hah&#803;at&#773;&#275;&#702;t&#257; &#702;et yisr&#257;&#702;&#275;l</em>) is the key indictment of every northern king from Jeroboam onward: the leader who leads the covenant people into violation bears amplified accountability. Christ bears this accountability in reverse &#8212; not as the one who causes others to sin but as the one who bears the consequence of their sin (Isa 53:6: &lsquo;the LORD has laid on him the iniquity of us all&rsquo;).</p>"
}
}

